var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……당주님, 완전히 포위됐습니다.","JPN":"……当主、完全に包囲されました。","ENG":"...My lady, we are completely surrounded.","TWN":"……堂主，我們被包圍了。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"이렇게 쉽게 당하다니 실망이군요, 당주님.","JPN":"これほどあっけなく捕まるとはがっかりですな、ご当主。","ENG":"I am rather disappointed you were this easy to catch, Lady Nanahara.","TWN":"竟然這麼輕易就栽到我們手裡，我對你太失望了，堂主。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"바람의 목소리를 잃어버린 것입니까?","JPN":"風の声を失ってしまったのですかな？","ENG":"Did you lose your ability to hear the voice of wind?","TWN":"你失去風聲了嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하바키…… 가문연합이 그대 같은 배반자를 품은 것은 씻을 수 없는 오명입니다.","JPN":"覇吐……連合があなたのような裏切り者を抱えていたことはそそぐことのできない汚名です。","ENG":"Habaki... You are the disgrace our Alliance cannot wash away. Traitor!","TWN":"幅木……你這個叛徒，你是家族聯盟永遠無法洗清的汙點。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"배반이 아니라 개혁입니다. 당주님의 빈 자리는 제가 곧 채우게 될 테니까요.","JPN":"裏切りではなく、改革です。ご当主の空席はもうすぐ私が埋めることになるでしょう。","ENG":"It is not betrayal, but reformation. Your vacant seat will soon be filled by me.","TWN":"這不是背叛，而是改革。堂主的空缺我很快就會補上。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그대는 그저 앞을 못 보는 평범한 악인일 뿐입니다. 아무도 당주로 인정하지 않을 거예요.","JPN":"あなたは先を見ることのできないただの悪人に過ぎません。誰も当主として認めないでしょう。","ENG":"You are just a senile man, unable to see what is ahead. No one will acknowledge you as their new leader.","TWN":"你不過就是個短視近利的惡人，沒有人會同意你當堂主的。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"허허, 누구라도 인정할 수밖에 없을 겁니다.","JPN":"フォッフォッ、みな認めざるを得ないはずです。","ENG":"Ha ha. They won't have a choice but to.","TWN":"呵呵，大家都只能同意。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그때가 되면 저는 미래를 듣는 수 십의 무녀들을 거느리고 있을 테니.","JPN":"その時になればわしは未来を聞く数十の巫女を連れているでしょうからな。","ENG":"For when the time comes, I will have tens of priestesses at my disposal to listen to the future.","TWN":"因為到時候，我手下就會有幾十個可以聽見未來的巫女。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……불경하군요.","JPN":"……無礼ですね。","ENG":"...The absurdity.","TWN":"……大膽！"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"전세는 이미 뒤집힌 것 같군.","JPN":"戦況はすでに傾いているようだな。","ENG":"The tables have turned.","TWN":"現在局勢對你不利，"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"저항하면 부상자만 늘어날 뿐이오. 이쯤에서 항복하는 게 어떻겠소?","JPN":"抵抗すれば怪我人が増えるだけだ。このくらいで降参してはどうだ？","ENG":"Resisting will only increase casualties. Is it not best to give up now?","TWN":"反抗只會徒增傷亡，不如就投降吧？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"지금입니다!","JPN":"今です！","ENG":"NOW!","TWN":"就是現在！"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"……음?","JPN":"……む？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>위장 차폐막 해제.</color>","JPN":"<color=#ffd34c>偽装シールドを解除。</color>","ENG":"<color=#ffd34c>Disabling Camouflage Shield.</color>","TWN":"<color=#ffd34c>卸除遮罩。</color>"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>태스크포스 노아의 위법행위를 확인. 추가병력은 보이지 않는다.</color>","JPN":"<color=#ffd34c>タスクフォース・ノアの違法行為を確認。追加兵力は見当たらない。</color>","ENG":"<color=#ffd34c>Illegal activity of TASKFORCE NOA confirmed. No additional troops detected.</color>","TWN":"<color=#ffd34c>特遣勢力諾亞的非法行為確認，沒有看到追加兵力。</color>"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현 시간부로 도시관리국 휘하 전 병력은 방위작전을 보류하고 태스크포스 노아에 대한 무력진압에 돌입한다.</color>","JPN":"<color=#ffd34c>現時点をもって都市管理局旗下の全兵力は防衛作戦を保留し、タスクフォース・ノアに対する武力鎮圧に突入。</color>","ENG":"<color=#ffd34c>As of now, all troops under the command of the City Management have been ordered to cease defense operations and begin the suppression of TASKFORCE NOA.</color>","TWN":"<color=#ffd34c>現在開始防衛作戰暫緩，城市管理局所有兵力對特遣勢力諾亞進行武力鎮壓。</color>"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"태스크포스 함선들? 대체 언제부터 숨어 있었던 거지?","JPN":"タスクフォースの艦船？　いったいいつから隠れていたんだ？","ENG":"TASKFORCE ships? Since when were they hiding here?","TWN":"特遣勢力艦船？什麼時候開始躲起來的？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};